import{_ as a,o as r,c as t,a2 as i}from"./chunks/framework.BFZItJIV.js";const p=JSON.parse('{"title":"S3 For XunRuiCMS相關","description":"","frontmatter":{},"headers":[],"relativePath":"tzh/about.md","filePath":"tzh/about.md"}'),l={name:"tzh/about.md"};function o(n,e,h,s,u,c){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="s3-for-xunruicms相關" tabindex="-1">S3 For XunRuiCMS相關 <a class="header-anchor" href="#s3-for-xunruicms相關" aria-label="Permalink to &quot;S3 For XunRuiCMS相關&quot;">​</a></h1><h2 id="結構介紹" tabindex="-1">結構介紹 <a class="header-anchor" href="#結構介紹" aria-label="Permalink to &quot;結構介紹&quot;">​</a></h2><p>S3 For XunRuiCMS 是為迅睿CMS系統提供AWS S3雲存儲支援的插件。</p><h2 id="運作特特性" tabindex="-1">運作特特性 <a class="header-anchor" href="#運作特特性" aria-label="Permalink to &quot;運作特特性&quot;">​</a></h2><ul><li>完整的文件傳輸傳輸管理功能</li><li>支持大文件分片傳輸传传输和斷傳片續傳續</li><li>与迅睿CMS文件管理系統系統无缝集成</li><li>完善的錯誤處理錯誤处理和日誌記錄記錄</li></ul><h2 id="安裝安裝要求" tabindex="-1">安裝安裝要求 <a class="header-anchor" href="#安裝安裝要求" aria-label="Permalink to &quot;安裝安裝要求&quot;">​</a></h2><ul><li><p>PHP 7.4 或更高版本</p></li><li><p>迅睿CMS ##或++</p></li></ul><h2 id="安裝安裝方式" tabindex="-1">安裝安裝方式 <a class="header-anchor" href="#安裝安裝方式" aria-label="Permalink to &quot;安裝安裝方式&quot;">​</a></h2><hr><p>通過迅睿CMS插件市場直接安裝</p><h2 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h2><p>. 安裝插件後，迅睿CMS後台配置 AWS S3 相關資訊 . . 啟用插件後，即可在迅睿CMS文件管理中使用 AWS S3 作為存儲</p><h2 id="文檔網站技術栈" tabindex="-1">文檔網站技術栈 <a class="header-anchor" href="#文檔網站技術栈" aria-label="Permalink to &quot;文檔網站技術栈&quot;">​</a></h2><p>本文檔網站基於以下技術構建：</p><p><strong>VitePress</strong> - �静態網站生成器，版本 ^^^11.1.1</p><ul><li>官網：<a href="https://vitepress.dev/" target="_blank" rel="noreferrer">https://vitepress.dev/</a></li><li>许可證：MIT License</li></ul><p><strong>VitepressPlugins.ImageViewer</strong> - 圖片查看器插件，版本 ^^^^11.1.6</p><ul><li>官網：<a href="https://github.com/noonnightrocker/vitepress-plugin-image-viewer" target="_blank" rel="noreferrer">https://github.com/noonnightrocker/vitepress-plugin-image-viewer</a></li><li>许可證：MIT License</li></ul><h2 id="致謝" tabindex="-1">致謝 <a class="header-anchor" href="#致謝" aria-label="Permalink to &quot;致謝&quot;">​</a></h2><p>感謝 Vue.js、Vite、VitePress 等開放原始碼專案的貢獻者。</p><h2 id="作者信息" tabindex="-1">作者信息 <a class="header-anchor" href="#作者信息" aria-label="Permalink to &quot;作者信息&quot;">​</a></h2><ul><li>著作者：陳延德</li><li>電子郵件：<a href="mailto:me@chenyande.com" target="_blank" rel="noreferrer">me@chenyande.com</a></li><li>網站：<a href="https://www.chenyande.com" target="_blank" rel="noreferrer">chenyande.com</a></li></ul><h2 id="使用權證" tabindex="-1">使用權證 <a class="header-anchor" href="#使用權證" aria-label="Permalink to &quot;使用權證&quot;">​</a></h2><p>本專案采用 Apache License 2.0授權</p><p>著作權 © 2025 - 2026 陳延德. 保留所有權利</p>',25)])])}const m=a(l,[["render",o]]);export{p as __pageData,m as default};
